package com.google.gson.internal.reflect;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;
import java.lang.reflect.Modifier;
import java.lang.reflect.Method;

import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class ReflectionHelperTest {

  static class TestRecord {
    public int x;
  }

  static class NonRecord {
  }

  private Field recordHelperField;
  private Object originalRecordHelper;
  private int originalModifiers;

  @BeforeEach
  void setUp() throws Exception {
    recordHelperField = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
    recordHelperField.setAccessible(true);

    // Save original value to restore later
    originalRecordHelper = recordHelperField.get(null);

    // Save original modifiers
    Field modifiersField = Field.class.getDeclaredField("modifiers");
    modifiersField.setAccessible(true);
    originalModifiers = recordHelperField.getModifiers();

    // Remove final modifier on RECORD_HELPER field
    modifiersField.setInt(recordHelperField, originalModifiers & ~Modifier.FINAL);
  }

  @AfterEach
  void tearDown() throws Exception {
    // Restore original RECORD_HELPER value and modifiers
    recordHelperField.set(null, originalRecordHelper);

    Field modifiersField = Field.class.getDeclaredField("modifiers");
    modifiersField.setAccessible(true);
    modifiersField.setInt(recordHelperField, originalModifiers);
  }

  @Test
  void isRecord_returnsTrue_whenRecordHelperReturnsTrue() throws Exception {
    Class<?> recordHelperType = recordHelperField.getType();

    // Create mock of RecordHelper interface/class
    Object mockRecordHelper = mock(recordHelperType);

    // Stub the isRecord method on mockRecordHelper to return true for TestRecord.class
    Method isRecordMethod = recordHelperType.getMethod("isRecord", Class.class);
    when(isRecordMethod.invoke(mockRecordHelper, TestRecord.class)).thenReturn(true);

    // Instead of using when().thenReturn() on reflection invoke (which calls actual method),
    // use Mockito's doReturn on the mock object's method directly:
    // So we stub the method on the mock object by using Mockito's Answer on the method:
    // But since we can't do that easily, we use a proxy mock with Mockito's withSettings().defaultAnswer()

    // Replace the RECORD_HELPER field with the mock
    recordHelperField.set(null, mockRecordHelper);

    // We need to stub the isRecord method properly on the mock. Since it's an interface or class,
    // we can use Mockito's when on the mock itself:
    // Cast mockRecordHelper to Object and use Mockito's when on the method via reflection proxy:
    // But simpler: create a spy with a real method and override isRecord.

    // To fix the issue, create a dynamic proxy mock with Mockito that stubs the isRecord method:

    // But simpler approach:
    // Use Mockito's doReturn(true).when(mockRecordHelper).isRecord(TestRecord.class);
    // But the method is not visible, so use reflection to get Method and stub it via Mockito's "when" on mock:

    // Use Mockito's mock with RETURNS_DEEP_STUBS and stub the method chain:
    // But here, we can create a Mockito mock with RETURNS_DEFAULTS and stub method via reflection:

    // Instead, use Mockito's "mock" with invocation handler:
    // So let's create a mock with an Answer that returns true for isRecord(TestRecord.class), false otherwise:

    Object proxyMock = java.lang.reflect.Proxy.newProxyInstance(
        recordHelperType.getClassLoader(),
        new Class<?>[] {recordHelperType},
        (proxy, method, args) -> {
          if ("isRecord".equals(method.getName()) && args != null && args.length == 1) {
            if (args[0] == TestRecord.class) {
              return true;
            }
            return false;
          }
          return method.invoke(originalRecordHelper, args);
        });

    recordHelperField.set(null, proxyMock);

    boolean result = ReflectionHelper.isRecord(TestRecord.class);

    assertTrue(result);
  }

  @Test
  void isRecord_returnsFalse_whenRecordHelperReturnsFalse() throws Exception {
    Class<?> recordHelperType = recordHelperField.getType();

    Object proxyMock = java.lang.reflect.Proxy.newProxyInstance(
        recordHelperType.getClassLoader(),
        new Class<?>[] {recordHelperType},
        (proxy, method, args) -> {
          if ("isRecord".equals(method.getName()) && args != null && args.length == 1) {
            if (args[0] == NonRecord.class) {
              return false;
            }
            return true;
          }
          return method.invoke(originalRecordHelper, args);
        });

    recordHelperField.set(null, proxyMock);

    boolean result = ReflectionHelper.isRecord(NonRecord.class);

    assertFalse(result);
  }
}
